     9→
    10→export type FilterType = "select" | "date_time";
    11→
    12→export type FilterSpec = SelectorFilterSpec | DateTimeFilterSpec;
    13→
    14→/**
    15→ * Map comparator -> expression template.
    16→ *
    17→ * Supported placeholders (replaced by DashboardFilterComponent):
    18→ * - {name}        : converted column name (see nameConverter)
    19→ * - {value}       : single value as escaped SQL string literal (including quotes)
    20→ * - {values}      : comma-joined escaped SQL string literals (e.g. 'a','b')
    21→ * - {valuesArray} : ClickHouse array literal (e.g. ['a','b'])
    22→ */
    23→export type ExpressionTemplateMap = Partial<Record<string, string>>;
    24→
    25→export type FilterDataSource =
    26→  | {
    27→      type: "inline";
    28→      values: Array<{ label: string; value: string }>;
    29→    }
    30→  | {
    31→      type: "sql";
    32→      sql: string;
    33→    };
    34→
    35→export interface SelectorFilterSpec {
    36→  filterType: "select";
    37→  name: string;
    38→  displayText: string;
    39→  /**
    40→   * Data source for loading selector values.
    41→   * - If type is "inline", uses the provided values array directly.
    42→   * - If type is "sql", uses the SQL query template to fetch options from the backend.
    43→   *
    44→   * For SQL data sources, supported template params (replaced by DashboardFilterComponent):
    45→   * - {from:String}, {to:String}, {rounding:UInt32}, {seconds:UInt32}, {startTimestamp:UInt32}, {endTimestamp:UInt32}
    46→   *   (same behavior as SQLQueryBuilder time span replacement)
    47→   * - {filterExpression:String} -> combined expression from previous selectors (or "1=1" if empty)
    48→   * - {timeFilter:String} -> generated from the date_time filter spec (or default time column if missing)
    49→   *
    50→   * The query should return a single-column result set; the first column is used as the selector value.
    51→   */
    52→  datasource: FilterDataSource;
    53→
    54→  // If not given, all comparators are supported
    55→  // See ComparatorManager for supported comparators
    56→  supportedComparators?: string[];
    57→
    58→  // Default to true is missing
    59→  onPreviousFilters?: boolean;
    60→
    61→  // Callback to convert name to the name in the expression
    62→  nameConverter?: (name: string) => string;
    63→
    64→  /**
    65→   * Optional comparator -> expression template map.
    66→   * If set (and comparator matches), it overrides `QueryPattern.toQueryString()`.
    67→   *
    68→   * Useful for array columns, e.g.:
    69→   * - "=": "has({name}, {value})"
    70→   * - "in": "hasAny({name}, {valuesArray})"
    71→   */
    72→  expressionTemplate?: ExpressionTemplateMap;
    73→
    74→  /**
    75→   * Optional initial filter pattern to apply when the component mounts.
    76→   * If provided, this filter will be automatically applied on initialization.
    77→   *
    78→   * Example:
    79→   * - { comparator: "!=", values: ["QueryStart"] } for `type <> 'QueryStart'`
    80→   * - { comparator: "in", values: ["value1", "value2"] } for `type IN ('value1', 'value2')`
    81→   */
    82→  defaultPattern?: {
    83→    comparator: string;
    84→    values: string[];
    85→  };
    86→}
    87→
    88→export interface DateTimeFilterSpec {
    89→  filterType: "date_time";
