     6→import { SqlUtils } from "@/lib/sql-utils";
     7→import { cn } from "@/lib/utils";
     8→import { RefreshCcw } from "lucide-react";
     9→import React, { Component } from "react";
    10→import Selector, { type SelectorRef } from "../selector";
    11→import type {
    12→  DateTimeFilterSpec,
    13→  FilterSpec,
    14→  SelectorFilterSpec,
    15→  SQLQuery,
    16→} from "./dashboard-model";
    17→import { SQLQueryBuilder } from "./sql-query-builder";
    18→import TimeSpanSelector, {
    19→  DisplayTimeSpan,
    20→  getDisplayTimeSpanByLabel,
    21→  type TimeSpan,
    22→} from "./timespan-selector";
    23→
    24→export interface SelectedFilter {
    25→  expr: string;
    26→  values: Map<string, QueryPattern>;
    27→}
    28→
    29→interface FilterProps {
    30→  className?: string;
    31→  filterSpecs: FilterSpec[];
    32→  defaultTimeSpan?: string;
    33→  showTimeSpanSelector?: boolean;
    34→  showRefresh?: boolean;
    35→  showAutoRefresh?: boolean;
    36→  onFilterChange?: (filter: SelectedFilter) => void;
    37→  onTimeSpanChange?: (range: TimeSpan) => void;
    38→  timezone?: string;
    39→
    40→  // Callback to load items for a filter selector
    41→  onLoadSourceData?: (query: SQLQuery) => Promise<string[]>;
    42→
    43→  children?: React.ReactNode;
    44→}
    45→
    46→type FilterState = Record<string, never>;
    47→
    48→class DashboardFilterComponent extends Component<FilterProps, FilterState> {
    49→  //
    50→  // These variables are NOT UI state, we don't define them in the react.state which would cause re-rendering when updating these states
    51→  //
    52→  // Track the selected filter and its values
    53→  private selectedFilters: Map<string, QueryPattern>;
    54→
    55→  // Track if one selector needs to re-load items
    56→  private reloadingRequiredState: Map<number, boolean>;
    57→
    58→  // Track the selected time span
    59→  private defaultTimeSpan: DisplayTimeSpan;
    60→  private timeSpanSelectorRef = React.createRef<TimeSpanSelector>();
    61→
    62→  private selectorContainerRef = React.createRef<HTMLDivElement>();
    63→  private scrollLeftButtonRef = React.createRef<HTMLButtonElement>();
    64→  private scrollRightButtonRef = React.createRef<HTMLButtonElement>();
    65→
    66→  // Store refs to Selector components by filter name
    67→  private selectorRefs = new Map<string, React.RefObject<SelectorRef | null>>();
    68→
    69→  private nameConverts: Map<string, (name: string) => string>;
    70→  private timeFilterSpec: DateTimeFilterSpec | undefined;
    71→  private filterSpecByName: Map<string, SelectorFilterSpec>;
    72→
    73→  constructor(props: FilterProps) {
    74→    super(props);
    75→
    76→    this.timeFilterSpec = props.filterSpecs.find(
    77→      (f): f is DateTimeFilterSpec => f.filterType === "date_time"
    78→    );
    79→    const defaultTimeSpanLabel =
    80→      this.timeFilterSpec?.defaultTimeSpan || props.defaultTimeSpan || "Last 15 Mins";
    81→    this.defaultTimeSpan = getDisplayTimeSpanByLabel(defaultTimeSpanLabel);
    82→
    83→    this.reloadingRequiredState = new Map();
    84→
    85→    this.selectedFilters = new Map<string, QueryPattern>();
    86→
    87→    this.nameConverts = new Map();
    88→    this.filterSpecByName = new Map();
    89→    props.filterSpecs.forEach((filter) => {
    90→      if (filter.filterType !== "select") {
    91→        return;
    92→      }
    93→      this.filterSpecByName.set(filter.name, filter);
    94→      if (filter.nameConverter) {
    95→        this.nameConverts.set(filter.name, filter.nameConverter);
    96→      } else {
    97→        this.nameConverts.set(filter.name, (name) => name);
    98→      }
    99→
   100→      // Initialize defaultPattern if provided
   101→      if (filter.defaultPattern) {
   102→        const comparator = ComparatorManager.parseComparator(filter.defaultPattern.comparator);
   103→        const isMultiValue = comparator.allowMultiValue ?? false;
   104→        const pattern = new QueryPattern(
   105→          isMultiValue,
   106→          filter.defaultPattern.comparator,
   107→          filter.defaultPattern.values
   108→        );
   109→        this.selectedFilters.set(filter.name, pattern);
   110→      }
   111→    });
   112→
   113→    this.onTimeSpanChangeCallback = this.onTimeSpanChangeCallback.bind(this);
   114→    this.onItemSelectedCallback = this.onItemSelectedCallback.bind(this);
   115→    this.beforeLoadItemCallback = this.beforeLoadItemCallback.bind(this);
   116→    this.afterLoadItemCallback = this.afterLoadItemCallback.bind(this);
   117→    this.onLoadItemCallback = this.onLoadItemCallback.bind(this);
   118→  }
   119→
   120→  componentDidMount(): void {
   121→    // Init the scroll button visibility
   122→    this.handleSelectorContainerScroll();
   123→
   124→    // const initialTimeSpan = this.getSelectedTimeSpan();
   125→    // if (this.props.onTimeSpanChange && initialTimeSpan) {
   126→    //   this.props.onTimeSpanChange(initialTimeSpan);
   127→    // }
   128→  }
   129→
   130→  componentDidUpdate(prevProps: FilterProps): void {
   131→    // Emit filter changes when filterSpecs change and defaultPatterns are initialized
   132→    if (this.props.filterSpecs !== prevProps.filterSpecs && this.props.onFilterChange) {
   133→      this.props.onFilterChange(this.getSelectedFilter());
   134→    }
   135→  }
   136→
   137→  shouldComponentUpdate(nextProps: FilterProps): boolean {
   138→    // Update the selected variables before rendering
   139→    if (this.props.filterSpecs !== nextProps.filterSpecs) {
   140→      this.selectedFilters = new Map<string, QueryPattern>();
   141→
   142→      this.timeFilterSpec = nextProps.filterSpecs.find(
   143→        (f): f is DateTimeFilterSpec => f.filterType === "date_time"
   144→      );
   145→      this.nameConverts = new Map();
   146→      this.filterSpecByName = new Map();
   147→      nextProps.filterSpecs.forEach((filter) => {
   148→        if (filter.filterType !== "select") {
   149→          return;
   150→        }
   151→        this.filterSpecByName.set(filter.name, filter);
   152→        if (filter.nameConverter) {
   153→          this.nameConverts.set(filter.name, filter.nameConverter);
   154→        } else {
   155→          this.nameConverts.set(filter.name, (name) => name);
   156→        }
   157→
   158→        // Initialize defaultPattern if provided
   159→        if (filter.defaultPattern) {
   160→          const comparator = ComparatorManager.parseComparator(filter.defaultPattern.comparator);
   161→          const isMultiValue = comparator.allowMultiValue ?? false;
   162→          const pattern = new QueryPattern(
   163→            isMultiValue,
   164→            filter.defaultPattern.comparator,
   165→            filter.defaultPattern.values
   166→          );
   167→          this.selectedFilters.set(filter.name, pattern);
   168→        }
   169→      });
   170→    }
   171→
   172→    // The default implementation
   173→    return true;
   174→  }
   175→
   176→  onTimeSpanChangeCallback(newSelected: DisplayTimeSpan) {
   177→    // Reset all selectors to allow re-loading
   178→    this.reloadingRequiredState.clear();
   179→
   180→    // Broadcast the change to the parent component
   181→    if (this.props.onTimeSpanChange) {
   182→      this.props.onTimeSpanChange(newSelected.getTimeSpan());
   183→    }
   184→  }
   185→
   186→  onItemSelectedCallback = (
   187→    index: number,
   188→    filterSpec: SelectorFilterSpec,
   189→    pattern: QueryPattern
   190→  ) => {
   191→    const { filterSpecs, onFilterChange } = this.props;
   192→
   193→    // Treat null or patterns with empty values as clearing the filter
   194→    if (pattern === null || pattern.values.length === 0) {
   195→      this.selectedFilters.delete(filterSpec.name);
   196→    } else {
   197→      this.selectedFilters.set(filterSpec.name, pattern);
   198→    }
   199→
   200→    // Clear other filter states so that they will be reloaded
   201→    for (let i = index + 1; i < filterSpecs.length; i++) {
   202→      this.reloadingRequiredState.set(i, true);
   203→    }
   204→
   205→    // Notification
   206→    if (onFilterChange) {
   207→      let queryExpression = "";
   208→      this.selectedFilters.forEach((pattern, alias) => {
   209→        if (queryExpression.length > 0) {
   210→          queryExpression += " AND ";
   211→        }
   212→        queryExpression += this.toFilterExpression(alias, pattern);
   213→      });
   214→
   215→      onFilterChange({ expr: queryExpression, values: this.selectedFilters });
   216→    }
   217→  };
   218→
   219→  beforeLoadItemCallback(index: number): boolean {
   220→    const isReloadingRequired = this.reloadingRequiredState.get(index);
   221→    return isReloadingRequired === undefined ? true : isReloadingRequired;
   222→  }
   223→
   224→  afterLoadItemCallback(index: number) {
   225→    this.reloadingRequiredState.set(index, false);
   226→  }
   227→
   228→  async onLoadItemCallback(filterIndex: number) {
   229→    const { filterSpecs, onLoadSourceData } = this.props;
   230→    const thisFilterSpec = filterSpecs[filterIndex];
   231→    if (thisFilterSpec.filterType !== "select") {
   232→      return [];
   233→    }
   234→
   235→    // Handle inline data source
   236→    if (thisFilterSpec.datasource.type === "inline") {
   237→      return thisFilterSpec.datasource.values;
   238→    }
   239→
   240→    // Handle SQL data source
   241→    const filterExpressionList = [];
   242→
   243→    // Apply other selectors' values as filter
   244→    if (thisFilterSpec.onPreviousFilters === undefined || thisFilterSpec.onPreviousFilters) {
   245→      for (let p = 0; p < filterIndex; p++) {
   246→        const otherFilterSpec = filterSpecs[p];
   247→        if (otherFilterSpec.filterType !== "select") {
   248→          continue;
   249→        }
   250→        const pattern = this.selectedFilters.get(otherFilterSpec.name);
   251→        if (pattern !== undefined && pattern !== null && pattern.values.length > 0) {
   252→          filterExpressionList.push(this.toFilterExpression(otherFilterSpec.name, pattern));
   253→        }
   254→      }
   255→    }
   256→
   257→    if (!onLoadSourceData) {
   258→      return [];
   259→    }
   260→
   261→    // Use SQLQueryBuilder for clean SQL transformation
   262→    const sql = new SQLQueryBuilder(thisFilterSpec.datasource.sql)
   263→      .timeSpan(this.getSelectedTimeSpan(), this.props.timezone ?? "UTC")
   264→      .filterExpression(filterExpressionList.join(" AND "))
   265→      .build();
   266→
   267→    const dimensions = await onLoadSourceData({
   268→      sql,
   269→    });
   270→
   271→    return dimensions.map((dim) => ({
   272→      value: dim,
   273→      label: dim,
   274→    }));
   275→  }
   276→
   277→  public getSelectedFilter(): SelectedFilter {
   278→    let expr = "";
   279→    this.selectedFilters.forEach((pattern, alias) => {
   280→      if (expr.length > 0) {
   281→        expr += " AND ";
   282→      }
   283→      expr += this.toFilterExpression(alias, pattern);
   284→    });
   285→    return { expr: expr, values: this.selectedFilters };
   286→  }
   287→
   288→  private asSqlString(value: string): string {
   289→    return `'${SqlUtils.escapeSqlString(value)}'`;
   290→  }
   291→
   292→  private replaceAllLiteral(input: string, token: string, value: string): string {
   293→    // Avoid regex replacement; tokens are literals like "{value}".
   294→    return input.split(token).join(value);
   295→  }
   296→
   297→  private buildExpressionFromTemplate(
   298→    template: string,
   299→    name: string,
   300→    pattern: QueryPattern
   301→  ): string {
   302→    const values = pattern.values ?? [];
   303→    const value = this.asSqlString(values[0] ?? "");
   304→    const valuesList = values.map((v) => this.asSqlString(v)).join(",");
   305→    const valuesArray = `[${valuesList}]`;
   306→
   307→    let result = template;
   308→    result = this.replaceAllLiteral(result, "{name}", name);
   309→    result = this.replaceAllLiteral(result, "{value}", value);
   310→    result = this.replaceAllLiteral(result, "{values}", valuesList);
   311→    result = this.replaceAllLiteral(result, "{valuesArray}", valuesArray);
   312→    return result;
   313→  }
   314→
   315→  private toFilterExpression(alias: string, pattern: QueryPattern): string {
   316→    const converter = this.nameConverts.get(alias) ?? ((name: string) => name);
   317→    const name = converter(alias);
   318→
   319→    const spec = this.filterSpecByName.get(alias);
   320→    const template = spec?.expressionTemplate?.[pattern.comparator];
   321→    if (template && template.length > 0) {
   322→      return this.buildExpressionFromTemplate(template, name, pattern);
   323→    }
   324→
   325→    return pattern.toQueryString(name);
   326→  }
   327→
   328→  public getSelectedTimeSpan(): TimeSpan {
   329→    // If all time span components are disabled, return a default time span
   330→    if (
   331→      this.props.showTimeSpanSelector === false &&
   332→      this.props.showRefresh === false &&
   333→      this.props.showAutoRefresh === false
   334→    ) {
   335→      // Return a default 1 hour timespan from now
   336→      const now = new Date();
   337→      const oneHourAgo = new Date(now.getTime() - 60 * 60 * 1000);
   338→      return {
   339→        startISO8601: oneHourAgo.toISOString(),
   340→        endISO8601: now.toISOString(),
   341→      };
   342→    }
   343→
   344→    // If time span selector specifically is disabled but others are enabled, still return default
   345→    if (this.props.showTimeSpanSelector === false || !this.timeSpanSelectorRef.current) {
   346→      const now = new Date();
   347→      const oneHourAgo = new Date(now.getTime() - 60 * 60 * 1000);
   348→      return {
   349→        startISO8601: oneHourAgo.toISOString(),
   350→        endISO8601: now.toISOString(),
   351→      };
   352→    }
   353→
   354→    return this.timeSpanSelectorRef.current?.getSelectedTimeSpan().getTimeSpan();
   355→  }
   356→
   357→  public setSelectedTimeSpan(timeSpan: TimeSpan) {
   358→    if (this.props.showTimeSpanSelector === false || !this.timeSpanSelectorRef.current) {
   359→      return; // Do nothing if time span selector is disabled
   360→    }
   361→    const label = `${timeSpan.startISO8601} - ${timeSpan.endISO8601}`;
   362→
   363→    this.timeSpanSelectorRef.current?.setSelectedTimeSpan(getDisplayTimeSpanByLabel(label));
   364→  }
   365→
   366→  public setFilter(filterName: string, value: string) {
   367→    const filterSpec = this.filterSpecByName.get(filterName);
   368→    if (!filterSpec) {
   369→      return; // Filter not found
   370→    }
   371→
   372→    // Create a QueryPattern with the value
   373→    const comparator = ComparatorManager.parseComparator("=");
   374→    const pattern = new QueryPattern(false, comparator.name, [value]);
   375→
   376→    // Update UI state directly via ref
   377→    const selectorRef = this.selectorRefs.get(filterName);
   378→    if (selectorRef?.current) {
   379→      selectorRef.current.setPattern(pattern);
   380→    }
   381→
   382→    // Find the index of this filter in the filterSpecs array
   383→    const filterIndex = this.props.filterSpecs.findIndex((f) => f === filterSpec);
   384→    if (filterIndex !== -1) {
   385→      // Trigger the callback to notify parent component
   386→      this.onItemSelectedCallback(filterIndex, filterSpec, pattern);
   387→    }
   388→  }
   389→
   390→  private handleSelectorContainerScroll = () => {
   391→    if (this.selectorContainerRef.current) {
   392→      const { scrollLeft, scrollWidth, clientWidth } = this.selectorContainerRef.current;
   393→
   394→      // Show left button if scrolled
   395→      // Directly control the DOM to avoid re-rendering
   396→      this.scrollLeftButtonRef.current?.classList.toggle("hidden", scrollLeft <= 0);
   397→
   398→      // Show right button if not fully scrolled to the right
   399→      // Directly control the DOM to avoid re-rendering
   400→      this.scrollRightButtonRef.current?.classList.toggle(
   401→        "hidden",
   402→        scrollLeft + clientWidth >= scrollWidth
   403→      );
   404→    }
   405→  };
   406→
   407→  private scrollLeft = () => {
   408→    if (this.selectorContainerRef.current) {
   409→      this.selectorContainerRef.current.scrollBy({ left: -200, behavior: "smooth" });
   410→    }
   411→  };
   412→
   413→  private scrollRight = () => {
   414→    if (this.selectorContainerRef.current) {
   415→      this.selectorContainerRef.current.scrollBy({ left: 200, behavior: "smooth" });
   416→    }
   417→  };
   418→
   419→  private handleRefreshTimeSpan = () => {
   420→    const selected = this.timeSpanSelectorRef.current?.getSelectedTimeSpan();
   421→    if (!selected) {
   422→      return;
   423→    }
   424→    // Recalculate "last N mins/hours" spans and emit to parent.
   425→    selected.reCalculateTimeSpan();
   426→    this.onTimeSpanChangeCallback(selected);
   427→  };
   428→
   429→  render() {
   430→    // Logger.trace("Rendering DashboardFilterComponent");
   431→
   432→    const { className, filterSpecs } = this.props;
   433→    const hasTimeFilterSpec = filterSpecs.some((f) => f.filterType === "date_time");
   434→
   435→    return (
   436→      <div className={cn("flex items-center justify-between gap-2", className)}>
   437→        <div
   438→          ref={this.selectorContainerRef}
   439→          onScroll={this.handleSelectorContainerScroll}
   440→          className="relative flex items-center overflow-x-auto whitespace-nowrap flex-1"
   441→        >
   442→          {filterSpecs.map((filter, index) => {
   443→            if (filter.filterType === "date_time") {
   444→              const timeFilterInputId = `time-filter-${filter.alias}`;
   445→              return (
   446→                <div key={filter.alias} className="shrink-0">
   447→                  <div className="relative">
   448→                    <FloatingLabel
   449→                      htmlFor={timeFilterInputId}
   450→                      className="pointer-events-none bg-transparent dark:bg-transparent"
   451→                    >
   452→                      {filter.timeColumn}
   453→                    </FloatingLabel>
   454→                    <TimeSpanSelector
   455→                      ref={this.timeSpanSelectorRef}
   456→                      defaultTimeSpan={this.defaultTimeSpan}
   457→                      showTimeSpanSelector={true}
   458→                      showRefresh={false}
   459→                      showAutoRefresh={false}
   460→                      size="sm"
   461→                      buttonClassName="h-8 rounded-r-none"
   462→                      onSelectedSpanChanged={this.onTimeSpanChangeCallback}
   463→                    />
   464→                  </div>
   465→                </div>
   466→              );
   467→            }
   468→
   469→            // Get or create ref for this selector
   470→            if (!this.selectorRefs.has(filter.name)) {
   471→              this.selectorRefs.set(filter.name, React.createRef<SelectorRef>());
   472→            }
   473→            const selectorRef = this.selectorRefs.get(filter.name)!;
   474→
   475→            return (
   476→              <Selector
   477→                ref={selectorRef}
   478→                className={cn("h-8", {
   479→                  "rounded-l": index === 0,
   480→                  "rounded-r": index === filterSpecs.length - 1,
   481→                  "rounded-l rounded-r": index === 0 && index === filterSpecs.length - 1,
   482→                })}
   483→                placeholder={filter.displayText ? filter.displayText : filter.name}
   484→                key={filter.name}
   485→                defaultItems={[]}
   486→                defaultPattern={this.selectedFilters.get(filter.name)}
   487→                supportedComparators={filter.supportedComparators}
   488→                beforeLoadItem={() => this.beforeLoadItemCallback(index)}
   489→                onLoadItem={() => this.onLoadItemCallback(index)}
   490→                afterLoadItem={() => this.afterLoadItemCallback(index)}
   491→                onItemSelected={(pattern) => this.onItemSelectedCallback(index, filter, pattern)}
   492→              />
   493→            );
   494→          })}
   495→        </div>
   496→
   497→        <div className="flex items-center gap-1 right-0">
   498→          {this.props.children}
   499→
   500→          {hasTimeFilterSpec && (
   501→            <Button
   502→              type="button"
   503→              variant="outline"
   504→              className="h-8 w-8 p-0"
   505→              aria-label="Refresh"
   506→              title="Refresh"
   507→              onClick={this.handleRefreshTimeSpan}
   508→            >
   509→              <RefreshCcw className="h-4 w-4" />
   510→            </Button>
   511→          )}
   512→
   513→          {!hasTimeFilterSpec &&
   514→            (this.props.showTimeSpanSelector !== false ||
   515→              this.props.showRefresh !== false ||
   516→              this.props.showAutoRefresh !== false) && (
   517→              <TimeSpanSelector
   518→                ref={this.timeSpanSelectorRef}
   519→                defaultTimeSpan={this.defaultTimeSpan}
   520→                size="sm"
   521→                showTimeSpanSelector={this.props.showTimeSpanSelector}
   522→                showRefresh={this.props.showRefresh}
   523→                showAutoRefresh={this.props.showAutoRefresh}
   524→                onSelectedSpanChanged={this.onTimeSpanChangeCallback}
   525→              />
   526→            )}
   527→        </div>
   528→      </div>
   529→    );
   530→  }
   531→}
   532→
   533→export default DashboardFilterComponent;
