**Step 1: Write the layout provider**

Create `src/components/shared/dashboard/dashboard-layout-provider.tsx`:

```typescript
"use client";

import React, { createContext, useCallback, useContext, useEffect, useMemo, useRef, useState } from 'react';
import type { Layout, Layouts } from 'react-grid-layout';
import { loadDashboardLayout, saveDashboardLayout, clearDashboardLayout } from './dashboard-layout-storage';

interface DashboardLayoutContextValue {
  layouts: Layouts;
  onLayoutChange: (currentLayout: Layout[], allLayouts: Layouts) => void;
  resetLayout: () => void;
  isEditing: boolean;
}

const DashboardLayoutContext = createContext<DashboardLayoutContextValue | null>(null);

interface DashboardLayoutProviderProps {
  dashboardId: string;
  defaultLayouts: Layouts;
  children: React.ReactNode;
}

export function DashboardLayoutProvider({
  dashboardId,
  defaultLayouts,
  children,
}: DashboardLayoutProviderProps) {
  const [layouts, setLayouts] = useState<Layouts>(() => {
    const saved = loadDashboardLayout(dashboardId);
    return saved ?? defaultLayouts;
  });

  // Debounce save to localStorage
  const saveTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  const onLayoutChange = useCallback(
    (currentLayout: Layout[], allLayouts: Layouts) => {
      setLayouts(allLayouts);

      // Debounced save
      if (saveTimeoutRef.current) {
        clearTimeout(saveTimeoutRef.current);
      }
      saveTimeoutRef.current = setTimeout(() => {
        saveDashboardLayout(dashboardId, {
          lg: allLayouts.lg ?? [],
          md: allLayouts.md ?? [],
          sm: allLayouts.sm ?? [],
        });
      }, 500);
    },
    [dashboardId]
  );

  const resetLayout = useCallback(() => {
    clearDashboardLayout(dashboardId);
    setLayouts(defaultLayouts);
  }, [dashboardId, defaultLayouts]);

  // Cleanup timeout on unmount
  useEffect(() => {
    return () => {
      if (saveTimeoutRef.current) {
        clearTimeout(saveTimeoutRef.current);
      }
    };
  }, []);

  const value = useMemo<DashboardLayoutContextValue>(
    () => ({
      layouts,
      onLayoutChange,
      resetLayout,
      isEditing: true, // Always editable for now
    }),
    [layouts, onLayoutChange, resetLayout]
  );

  return (
    <DashboardLayoutContext.Provider value={value}>
      {children}
    </DashboardLayoutContext.Provider>
  );
}

export function useDashboardLayout(): DashboardLayoutContextValue {
  const ctx = useContext(DashboardLayoutContext);
  if (!ctx) {
    throw new Error('useDashboardLayout must be used within DashboardLayoutProvider');
  }
  return ctx;
}

export function useDashboardLayoutOptional(): DashboardLayoutContextValue | null {
  return useContext(DashboardLayoutContext);
}
```

